import { useSelector, useDispatch } from "react-redux";
import { cartAction } from "../../store";

const CartButton = (props) => {
	return (
		<button className={classes.button}>
			<span>My Cart</span>
			<span className={classes.badge}>1</span>
		</button>
	);
};

export default CartButton;
